public class NewDevKit_Action extends BaseAction {
  private static final Icon ICON = MPSIcons.Nodes.DevKit;

  public NewDevKit_Action() {
    super("DevKit", "", ICON);
    this.setIsAlwaysVisible(false);
    this.setExecuteOutsideCommand(true);
    updateInBackground(true);
  }
  @Override
  public boolean isDumbAware() {
    return true;
  }
  @Override
  protected boolean collectActionData(AnActionEvent event, final Map<String, Object> _params) {
    if (!(super.collectActionData(event, _params))) {
      return false;
    }
    {
      MPSProject p = event.getData(MPSCommonDataKeys.MPS_PROJECT);
      if (p == null) {
        return false;
      }
    }
    {
      String p = event.getData(MPSDataKeys.NAMESPACE);
    }
    return true;
  }
  @Override
  public void doExecute(@NotNull final AnActionEvent event, final Map<String, Object> _params) {
    final MPSProject mpsProject = event.getData(MPSCommonDataKeys.MPS_PROJECT);
    final String virtualFolder = event.getData(MPSDataKeys.NAMESPACE);
    final NameLocationPanel cfg = new NameLocationPanel(NewModuleDialog.projectHome(mpsProject), "Devkit name:", "Devkit file location:");
    cfg.withDefaults("NewDevkit", "devkits");
    NewModuleDialog<DevKit> dialog = new NewModuleDialog<>(mpsProject, cfg);
    dialog.withCheck(() -> NewModuleUtil.check(mpsProject, MPSExtentions.DOT_DEVKIT, cfg.getModuleName(), cfg.getModuleLocation().getAbsolutePath()));
    dialog.withFactory(() -> {
      String devkitName = cfg.getModuleName();
      File devkitLocation = cfg.getModuleLocation();
      DevKit result = new DevkitProducer(mpsProject).create(devkitName, mpsProject.getFileSystem().getFile(devkitLocation));
      mpsProject.setVirtualFolder(result, virtualFolder);
      return result;
    });

    dialog.setTitle("New Devkit");
    dialog.show();
    if (!(dialog.isOK())) {
      return;
    }

    DevKit devkit = dialog.getResult();
    if (devkit == null) {
      return;
    }

    ProjectPane projectPane = ProjectPane.getInstance(mpsProject);
    projectPane.selectModule(devkit, false);
  }
}
